INSERT INTO site_pages (slug, page_type, title, body, is_published) VALUES ('home', 'landing_hero', 'MDRank — Data-Driven Device Rankings', 'Independent hands-on evaluations across Blood Pressure, Respiratory, Sleep, Pain Relief, and Temperature categories.', TRUE) ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, body = EXCLUDED.body;
INSERT INTO devices (id, slug, source_url, name, manufacturer, mdrank_score, fda_status, connectivity, retail_price, spec_json, image_url, overview, key_features, is_editors_choice, is_synthetic, rank_in_subcategory, is_published) VALUES ('c1540d43-bef2-4aa6-939b-acdea47f2d2e', 'truevitals-bp-pro', NULL, 'TrueVitals BP Pro', 'TrueVitals', 99, 'fda_510k_cleared'::fda_status, 'Bluetooth 5.2, Wi-Fi', 129.0, '{"connectivity": "Bluetooth 5.2, Wi-Fi"}'::jsonb, NULL, 'The TrueVitals BP Pro is a premium upper-arm monitor engineered for clinical-grade home tracking with dual wireless sync and an oversized color display for at-a-glance readings.', '["FDA 510(k) cleared upper-arm monitor", "Dual-band Bluetooth 5.2 and Wi-Fi cloud sync", "Tri-sensor averaging for stable systolic/diastolic capture", "Dual-user profiles with clinician-ready PDF export", "Editor''s Choice \u2014 MDRank top pick for home BP monitoring"]'::jsonb, TRUE, TRUE, 1, TRUE) ON CONFLICT (slug) DO NOTHING;
INSERT INTO device_subcategories (device_id, subcategory_id, rank) SELECT 'c1540d43-bef2-4aa6-939b-acdea47f2d2e'::uuid, id, 1 FROM subcategories WHERE slug = 'blood-pressure-monitors' ON CONFLICT DO NOTHING;
INSERT INTO device_subcategories (device_id, subcategory_id, rank) SELECT 'c1540d43-bef2-4aa6-939b-acdea47f2d2e'::uuid, id, 1 FROM subcategories WHERE slug = 'upper-arm-monitors' ON CONFLICT DO NOTHING;
INSERT INTO reviews (id, device_id, slug, title, excerpt, strengths, limitations, recommend_if, avoid_if, is_published, published_at) VALUES ('2b207cc9-e2b7-427f-bb46-30ad71bc981c', 'c1540d43-bef2-4aa6-939b-acdea47f2d2e'::uuid, 'truevitals-bp-pro-hands-on-test', 'MDRank Hands-On Test: TrueVitals BP Pro', 'Our top-rated pick delivers exceptional measurement consistency, intuitive app workflows, and a premium build that sets the benchmark for home blood pressure monitoring in 2026.', '["Outstanding measurement repeatability across 480+ paired test readings", "Best-in-class app with trend charts and one-tap clinician sharing", "Comfortable wide-range cuff fits arms from 22\u201348 cm without gaps", "Fast inflation cycle completes most readings in under 25 seconds", "Editor''s Choice \u2014 highest MDRank score in the Blood Pressure category"]'::jsonb, '["Premium price point above budget-focused alternatives", "Full cloud features require account registration"]'::jsonb, '["You want the most accurate, feature-rich home BP monitor available", "You share readings with a physician or care team regularly", "Comfort and cuff fit across varied arm sizes matter to you"]'::jsonb, '["You need a bare-minimum budget cuff under $40", "You prefer a wrist-form factor device"]'::jsonb, TRUE, NOW()) ON CONFLICT (slug) DO NOTHING;
INSERT INTO review_sections (id, review_id, section_type, heading, body, sort_order) VALUES ('b0e29cc8-ee3f-4cd8-88dd-1085b9f4250d', '2b207cc9-e2b7-427f-bb46-30ad71bc981c'::uuid, 'clinical_summary'::review_section_type, 'MDRank Verdict', 'The TrueVitals BP Pro earned an MDRank Score of 99/100 — our highest rating among blood pressure monitors. Lab cross-checks and human-subject trials confirmed tight agreement with reference sphygmomanometry, while the companion app elevated day-to-day usability.', 0);
INSERT INTO review_sections (id, review_id, section_type, heading, body, sort_order) VALUES ('e9245495-a594-4374-ab44-eb8be3bd84c3', '2b207cc9-e2b7-427f-bb46-30ad71bc981c'::uuid, 'performance_metric'::review_section_type, 'Measurement Performance', 'Structured testing showed mean absolute error under 2 mmHg systolic across repeated seated trials. Irregular heartbeat flagging triggered appropriately without excessive false positives.', 1);
INSERT INTO review_sections (id, review_id, section_type, heading, body, sort_order) VALUES ('fa1113a7-1723-4f79-94d5-05894bda9726', '2b207cc9-e2b7-427f-bb46-30ad71bc981c'::uuid, 'clinical_recommendation'::review_section_type, 'Editor''s Choice Recommendation', 'MDRank designates the TrueVitals BP Pro as Editor''s Choice for home upper-arm monitoring. It balances clinical rigor, connectivity, and long-term value better than any competitor in our current rankings.', 2);
